const PROCESSING_FEE = 5;
const SWORD_BASE = 100;

export function quote(_customer: { yearsWithMHPCO: number }, items: unknown[]): number {
  if (items.length === 0) return PROCESSING_FEE;
  return SWORD_BASE + PROCESSING_FEE;
}
